using sv_58677750ce8045b29db1b7ed11c9a237.Models;

namespace sv_58677750ce8045b29db1b7ed11c9a237.Services;

/// <summary>
/// Scoped service that holds wizard data for a single user's circuit.
/// The circuit persists across page navigations when enhanced navigation is active,
/// so data entered on one step is available on subsequent steps.
/// </summary>
public class WizardState
{
    public PersonalInfoModel PersonalInfo { get; set; } = new();
    public List<ExperienceEntry> Experience { get; set; } = [new()];
    public List<ReferenceContact> References { get; set; } = [new()];

    public HashSet<int> CompletedSteps { get; } = [];

    public void MarkCompleted(int step) => CompletedSteps.Add(step);
    public bool IsCompleted(int step) => CompletedSteps.Contains(step);
}

