﻿@inherits LayoutComponentBase
@inject NavigationManager Nav

@{
    var steps = new (string Url, string Label)[]
    {
        ("/apply/personal-info", "Personal Info"),
        ("/apply/experience", "Experience"),
        ("/apply/references", "References"),
        ("/apply/review", "Review"),
    };
    var currentPath = new Uri(Nav.Uri).AbsolutePath.TrimEnd('/');
    var currentStep = Array.FindIndex(steps, s =>
        currentPath.Equals(s.Url, StringComparison.OrdinalIgnoreCase)) + 1;
    var isWizard = currentStep > 0;
}

<div class="page">
    <div class="sidebar">
        <NavMenu />
    </div>

    <main>
        <div class="top-row px-4">
            @if (isWizard)
            {
                <div class="d-flex align-items-center gap-3 w-100">
                    <strong>Step @currentStep of @steps.Length</strong>
                    <div class="progress flex-grow-1" style="height: 8px;">
                        <div class="progress-bar" role="progressbar"
                             style="width: @(currentStep * 100 / steps.Length)%">
                        </div>
                    </div>
                </div>
                <nav class="d-flex gap-2 ms-3">
                    @for (var i = 0; i < steps.Length; i++)
                    {
                        var step = steps[i];
                        var stepNum = i + 1;
                        var css = stepNum == currentStep ? "btn btn-primary btn-sm"
                                : stepNum < currentStep  ? "btn btn-outline-success btn-sm"
                                                         : "btn btn-outline-secondary btn-sm";
                        <a href="@step.Url" class="@css">@step.Label</a>
                    }
                </nav>
            }
            else
            {
                <a href="https://learn.microsoft.com/aspnet/core/" target="_blank">About</a>
            }
        </div>

        <article class="content px-4">
            @Body
        </article>
    </main>
</div>

<div id="blazor-error-ui" data-nosnippet>
    An unhandled error has occurred.
    <a href="." class="reload">Reload</a>
    <span class="dismiss">🗙</span>
</div>

