@page "/apply/personal-info"
@rendermode InteractiveServer
@inject sv_58677750ce8045b29db1b7ed11c9a237.Services.WizardState Wizard
@inject NavigationManager Nav

<PageTitle>Apply – Personal Info</PageTitle>

<h1>Step 1: Personal Info</h1>

<EditForm Model="Wizard.PersonalInfo" OnValidSubmit="Next" FormName="personal-info">
    <div class="mb-3">
        <label class="form-label">Full Name</label>
        <InputText class="form-control" @bind-Value="Wizard.PersonalInfo.Name" />
    </div>
    <div class="mb-3">
        <label class="form-label">Email</label>
        <InputText class="form-control" type="email" @bind-Value="Wizard.PersonalInfo.Email" />
    </div>
    <button type="submit" class="btn btn-primary">Next &rarr;</button>
</EditForm>

@code {
    private void Next()
    {
        Wizard.MarkCompleted(1);
        Nav.NavigateTo("/apply/experience");
    }
}

@page "/apply/experience"
@rendermode InteractiveServer
@inject sv_58677750ce8045b29db1b7ed11c9a237.Services.WizardState Wizard
@inject NavigationManager Nav

<PageTitle>Apply – Experience</PageTitle>

<h1>Step 2: Experience</h1>

<EditForm Model="Wizard" OnValidSubmit="Next" FormName="experience">
    @for (var i = 0; i < Wizard.Experience.Count; i++)
    {
        var entry = Wizard.Experience[i];
        <div class="card mb-3 p-3">
            <h5>Job @(i + 1)</h5>
            <div class="mb-2">
                <label class="form-label">Company</label>
                <InputText class="form-control" @bind-Value="entry.Company" />
            </div>
            <div class="mb-2">
                <label class="form-label">Title</label>
                <InputText class="form-control" @bind-Value="entry.Title" />
            </div>
            <div class="mb-2">
                <label class="form-label">Years</label>
                <InputText class="form-control" @bind-Value="entry.Years" />
            </div>
            @if (Wizard.Experience.Count > 1)
            {
                var index = i;
                <button type="button" class="btn btn-outline-danger btn-sm"
                        @onclick="() => RemoveEntry(index)">Remove</button>
            }
        </div>
    }

    <button type="button" class="btn btn-outline-secondary mb-3" @onclick="AddEntry">
        + Add another job
    </button>

    <div class="d-flex gap-2">
        <a href="/apply/personal-info" class="btn btn-outline-secondary">&larr; Back</a>
        <button type="submit" class="btn btn-primary">Next &rarr;</button>
    </div>
</EditForm>

@code {
    private void AddEntry() => Wizard.Experience.Add(new());

    private void RemoveEntry(int index) => Wizard.Experience.RemoveAt(index);

    private void Next()
    {
        Wizard.MarkCompleted(2);
        Nav.NavigateTo("/apply/references");
    }
}

