@page "/apply/review"
@rendermode InteractiveServer
@inject sv_58677750ce8045b29db1b7ed11c9a237.Services.WizardState Wizard

<PageTitle>Apply – Review</PageTitle>

<h1>Step 4: Review Your Application</h1>

<div class="card mb-3 p-3">
    <h4>Personal Info</h4>
    <dl class="row mb-0">
        <dt class="col-sm-3">Name</dt>
        <dd class="col-sm-9">@Wizard.PersonalInfo.Name</dd>
        <dt class="col-sm-3">Email</dt>
        <dd class="col-sm-9">@Wizard.PersonalInfo.Email</dd>
    </dl>
    <a href="/apply/personal-info" class="btn btn-sm btn-outline-secondary">Edit</a>
</div>

<div class="card mb-3 p-3">
    <h4>Experience</h4>
    @foreach (var job in Wizard.Experience)
    {
        <div class="mb-2 ps-2 border-start">
            <strong>@job.Title</strong> at @job.Company (@job.Years years)
        </div>
    }
    <a href="/apply/experience" class="btn btn-sm btn-outline-secondary">Edit</a>
</div>

<div class="card mb-3 p-3">
    <h4>References</h4>
    @foreach (var r in Wizard.References)
    {
        <div class="mb-2 ps-2 border-start">
            <strong>@r.Name</strong> — @r.Relationship, @r.Phone
        </div>
    }
    <a href="/apply/references" class="btn btn-sm btn-outline-secondary">Edit</a>
</div>

<div class="d-flex gap-2">
    <a href="/apply/references" class="btn btn-outline-secondary">&larr; Back</a>
    <button class="btn btn-success" @onclick="Submit">Submit Application</button>
</div>

@if (submitted)
{
    <div class="alert alert-success mt-3">Application submitted successfully!</div>
}

@code {
    private bool submitted;

    private void Submit()
    {
        Wizard.MarkCompleted(4);
        submitted = true;
    }
}

